// GraphRAG Enricher — возвращает только данные, без console.log
const message = $json.message || '';
const clientName = $json.client_name || '';

const recommendations = [];

if (message.toLowerCase().includes('ноутбук')) {
  recommendations.push('Рекомендуем приобрести чехол и мышь к ноутбуку');
}
if (message.toLowerCase().includes('мышь')) {
  recommendations.push('К мыши рекомендуем коврик');
}
if (clientName) {
  recommendations.push(`Для ${clientName} действует скидка 5% при заказе от 100 000 руб`);
}
if (recommendations.length === 0) {
  recommendations.push('Для подбора оптимальной комплектации обратитесь к нашему менеджеру');
}

// Возвращаем ТОЛЬКО объект, без console.log!
return {
  enrichment: {
    recommendations: recommendations
  }
};
